        if (type === 'array') {
            if (value.length === 0) return '[]';
            const items = value.map(v => formatValue(v, indent + 2)).join(',\n' + ' '.repeat(indent + 2));
            return '[\n' + ' '.repeat(indent + 2) + items + '\n' + ' '.repeat(indent) + ']';
        }
        if (type === 'object') {
            const keys = Object.keys(value);
            if (keys.length === 0) return '{}';
            const pairs = keys.map(k => k + ': ' + formatValue(value[k], indent + 2)).join(',\n' + ' '.repeat(indent + 2));
            return '{\n' + ' '.repeat(indent + 2) + pairs + '\n' + ' '.repeat(indent) + '}';
        }
        if (type === 'function') {
            return 'function() { ... }';
        }
        return String(value);
